-- ============================================================================
-- Quiz Seed: Numbers — Part 4 (Chapters 31–36)
-- 3 difficulties × 6 chapters = 96 total questions
--   kids:   3 per chapter  = 18
--   teens:  5 per chapter  = 30
--   adults: 8 per chapter  = 48
-- ============================================================================

-- ═══ Numbers Chapter 31 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 31, 'kids', 1, 'Who did God tell Moses to fight against in Numbers 31?', 'The Midianites', 'The Philistines', 'The Egyptians', 'The Amalekites', 'a', 'Numbers 31:2 — "Avenge the children of Israel of the Midianites: afterward shalt thou be gathered unto thy people."'),
('Numbers', 31, 'kids', 2, 'How many men were chosen from each tribe to go to war against Midian?', 'A thousand', 'Five hundred', 'Two thousand', 'A hundred', 'a', 'Numbers 31:4 — "Of every tribe a thousand, throughout all the tribes of Israel, shall ye send to the war."'),
('Numbers', 31, 'kids', 3, 'What happened to Balaam during the war against Midian?', 'He was captured and imprisoned', 'He escaped to Egypt', 'He was slain with the sword', 'He surrendered to Moses', 'a', 'Numbers 31:8 — "Balaam also the son of Beor they slew with the sword."'),
-- Teens
('Numbers', 31, 'teens', 1, 'What was Phinehas the priest sent with to accompany the army against Midian?', 'The holy instruments and the trumpets', 'The ark of the covenant', 'The tabernacle and its furnishings', 'Moses'' rod', 'a', 'Numbers 31:6 — "Moses sent them to the war...and Phinehas the son of Eleazar the priest...with the holy instruments, and the trumpets to blow in his hand."'),
('Numbers', 31, 'teens', 2, 'How many of Israel''s soldiers were slain in the battle against Midian?', 'Not one man', 'Twelve', 'One hundred', 'Fifty', 'a', 'Numbers 31:49 — "Thy servants have taken the sum of the men of war which are under our charge, and there lacketh not one man of us."'),
('Numbers', 31, 'teens', 3, 'Why was Moses angry with the officers when they returned from battle?', 'They had kept all the women alive', 'They had failed to bring back enough spoil', 'They had not consulted the priest', 'They had counted the spoil incorrectly', 'a', 'Numbers 31:15 — "And Moses said unto them, Have ye saved all the women alive?" — because the women caused Israel to sin at Baal-peor.'),
('Numbers', 31, 'teens', 4, 'What was required of warriors and captives who had killed anyone or touched a dead body?', 'To remain outside the camp seven days and purify themselves', 'To offer a burnt offering immediately', 'To fast for three days', 'To bathe in the river Jordan', 'a', 'Numbers 31:19 — "And do ye abide without the camp seven days: whosoever hath killed any person...purify both yourselves and your captives."'),
('Numbers', 31, 'teens', 5, 'How was the spoil of the war against Midian divided?', 'Half to the warriors and half to the congregation', 'All of it given to the priests', 'Two-thirds to the soldiers and one-third to the people', 'It was all consecrated to the LORD', 'a', 'Numbers 31:27 — "And divide the prey into two parts; between them that took the war upon them...and between all the congregation."'),
-- Adults
('Numbers', 31, 'adults', 1, 'What fraction of the warriors'' portion was given as a tribute to the LORD?', 'One out of every five hundred', 'One out of every fifty', 'One out of every hundred', 'One out of every thousand', 'a', 'Numbers 31:28 — "And levy a tribute unto the LORD of the men of war which went out to battle: one soul of five hundred, both of the persons, and of the beeves, and of the asses, and of the sheep."'),
('Numbers', 31, 'adults', 2, 'What fraction of the congregation''s half of the spoil was given to the Levites?', 'One out of every fifty', 'One out of every hundred', 'One out of every ten', 'One out of every five hundred', 'a', 'Numbers 31:30 — "And of the children of Israel''s half, thou shalt take one portion of fifty...and give them unto the Levites, which keep the charge of the tabernacle of the LORD."'),
('Numbers', 31, 'adults', 3, 'What was the total number of sheep taken as spoil from the Midianites?', 'Six hundred seventy and five thousand', 'Two hundred fifty thousand', 'One million', 'Thirty-two thousand', 'a', 'Numbers 31:36-37 — "And the half, which was the portion of them that went out to war, was in number three hundred thousand and seven and thirty thousand and five hundred sheep...And the LORD''s tribute of the sheep was six hundred and threescore and fifteen."'),
('Numbers', 31, 'adults', 4, 'What theological connection does Balaam''s death in this chapter have to Numbers 22-24?', 'Balaam died because he tried to curse Israel a second time', 'Balaam had counselled Midian to seduce Israel into sin at Baal-peor, so his death was divine judgment', 'Balaam led the Midianite army in battle', 'Balaam stole from the spoil of Israel', 'a', 'Numbers 31:16 — "Behold, these caused the children of Israel...to commit trespass against the LORD in the matter of Peor." Balaam''s counsel led to the apostasy that cost 24,000 lives (Num. 25).'),
('Numbers', 31, 'adults', 5, 'What process was prescribed for purifying metal objects captured from Midian?', 'Pass them through fire and then through the water of purification', 'Bury them in the ground for seven days', 'Wash them in the river and present them to the priest', 'Sprinkle them with the blood of a sin offering', 'a', 'Numbers 31:23 — "Every thing that may abide the fire, ye shall make it go through the fire...and all that abideth not the fire ye shall make go through the water."'),
('Numbers', 31, 'adults', 6, 'What is the "water of separation" mentioned in Numbers 31:23?', 'Water from the river Jordan used for ritual washing', 'The water made with the ashes of the red heifer for purification from corpse defilement', 'Rain water collected from the tabernacle', 'Water from the well at Beer used in blessing', 'a', 'Numbers 31:23 — "it shall be purified with the water of separation" — referring back to the red heifer ritual of Numbers 19, which purified from contact with the dead.'),
('Numbers', 31, 'adults', 7, 'What did the officers voluntarily bring to Moses as an atonement offering after counting their men?', 'Gold jewellery — armlets, bracelets, rings, earrings, and tablets', 'Silver from the spoil of Midian', 'The firstborn of every animal captured', 'Incense and fine flour', 'a', 'Numbers 31:50 — "We have therefore brought an oblation for the LORD, what every man hath gotten, of jewels of gold, chains, and bracelets, rings, earrings, and tablets."'),
('Numbers', 31, 'adults', 8, 'What typological significance do many scholars see in the fact that not one Israelite soldier died in the war against Midian?', 'It demonstrates that Israel was militarily superior to all nations', 'It prefigures Christ''s complete victory where none given to Him are lost', 'It proves the soldiers were holier than other Israelites', 'It fulfilled the Abrahamic covenant about warfare', 'a', 'Numbers 31:49 — "there lacketh not one man of us." The complete preservation of God''s people in holy war is seen as a type of Christ''s promise: "Of all which he hath given me I should lose nothing" (John 6:39).');

-- ═══ Numbers Chapter 32 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 32, 'kids', 1, 'Which two tribes asked Moses if they could stay on the east side of the Jordan River?', 'Reuben and Gad', 'Judah and Benjamin', 'Simeon and Levi', 'Dan and Naphtali', 'a', 'Numbers 32:1-2 — "Now the children of Reuben and the children of Gad had a very great multitude of cattle...And the children of Gad and the children of Reuben came and spake unto Moses."'),
('Numbers', 32, 'kids', 2, 'Why did Reuben and Gad want the land east of Jordan?', 'It was a good place for cattle', 'It had large cities they could move into', 'It was very close to Egypt', 'It had plenty of water', 'a', 'Numbers 32:4 — "The country which the LORD smote before the congregation of Israel, is a land for cattle, and thy servants have cattle."'),
('Numbers', 32, 'kids', 3, 'What did Reuben and Gad promise Moses they would do before settling in the east?', 'Help fight for the land of Canaan', 'Build a wall around the Jordan River', 'Send gifts to the other tribes', 'Guard the tabernacle in the wilderness', 'a', 'Numbers 32:17 — "We ourselves will go ready armed before the children of Israel, until we have brought them unto their place."'),
-- Teens
('Numbers', 32, 'teens', 1, 'To what sin did Moses compare the request of Reuben and Gad?', 'The sin of making the golden calf', 'The sin of the spies who discouraged the people from entering Canaan', 'The rebellion of Korah', 'The murmuring at the waters of Meribah', 'a', 'Numbers 32:8-9 — Moses compared it to when the fathers discouraged Israel''s heart at Kadesh-barnea so that they did not enter the land.'),
('Numbers', 32, 'teens', 2, 'What did Moses warn would happen to the whole nation if Reuben and Gad abandoned Israel during the conquest?', 'God would destroy them immediately', 'God''s anger would be kindled and Israel would wander longer', 'They would lose their inheritance in Canaan', 'The Canaanites would be stronger than Israel', 'a', 'Numbers 32:14-15 — "an increase of sinful men, to augment yet the fierce anger of the LORD...he will yet again leave them in the wilderness; and ye shall destroy all this people."'),
('Numbers', 32, 'teens', 3, 'What condition did Moses set for the tribes of Reuben and Gad receiving the land east of Jordan?', 'Every armed man must cross the Jordan and fight with Israel until Canaan was conquered', 'They had to pay tribute to the other tribes each year', 'They had to give up one city for the Levites first', 'Their firstborn sons had to go live in Canaan', 'a', 'Numbers 32:20-22 — "If ye will go armed over Jordan...and the land shall be subdued...then afterward ye shall return, and be guiltless."'),
('Numbers', 32, 'teens', 4, 'Which half tribe was also given land east of the Jordan alongside Reuben and Gad?', 'Half the tribe of Manasseh', 'Half the tribe of Ephraim', 'Half the tribe of Issachar', 'Half the tribe of Zebulun', 'a', 'Numbers 32:33 — "And Moses gave unto them, even to the children of Gad, and to the children of Reuben, and unto half the tribe of Manasseh the son of Joseph, the kingdom of Sihon...and the kingdom of Og."'),
('Numbers', 32, 'teens', 5, 'What was the agreement Reuben and Gad made regarding their families while the men went to war?', 'Their families would live in the fortified cities of the east while the men fought in Canaan', 'Their wives and children would cross the Jordan with the army', 'Their elders would rule in their absence', 'Their families would travel with the tabernacle', 'a', 'Numbers 32:16-17 — "We will build sheepfolds here for our cattle, and cities for our little ones...our little ones shall dwell in the fenced cities."'),
-- Adults
('Numbers', 32, 'adults', 1, 'What specific land areas were given to Gad and Reuben and half Manasseh?', 'The kingdoms of Sihon king of the Amorites and of Og king of Bashan', 'The entire Transjordan from the Arnon to Mount Hermon', 'The plains of Moab and all of Gilead', 'The land of Edom and the coastal territories', 'a', 'Numbers 32:33 — "Moses gave unto them...the kingdom of Sihon king of the Amorites, and the kingdom of Og king of Bashan, the land, with the cities thereof."'),
('Numbers', 32, 'adults', 2, 'What city did the children of Gad rebuild and rename, and what was its original name?', 'Dibon, renamed from Aroer', 'Nimrah, rebuilt as Beth-nimrah', 'Jazer, renamed from Jogbehah', 'Nebo, rebuilt from Ataroth', 'a', 'Numbers 32:34 — "And the children of Gad built Dibon, and Ataroth, and Aroer" — Ataroth is mentioned as a city they built, and the region is associated with the border areas of Sihon''s kingdom.'),
('Numbers', 32, 'adults', 3, 'What does Moses'' comparison to the spy narrative in Numbers 13-14 reveal about God''s standards of leadership?', 'Past sins are always held against leaders', 'Discouraging the faith and courage of God''s people carries generational consequences', 'Only the tribe of Levi could make decisions about land', 'God punishes the whole nation for one man''s sin', 'a', 'Numbers 32:11-13 — God swore none of the men who discouraged the congregation would see Canaan, and he let Israel wander forty years because of it. Leaders who sow fear bear responsibility for communal faithlessness.'),
('Numbers', 32, 'adults', 4, 'What phrase summarizes the moral warning Moses gives in Numbers 32:23?', 'Your sin will find you out', 'The LORD will punish you in this life and the next', 'No man can hide his sin from God forever', 'Sin separates you from the presence of God', 'a', 'Numbers 32:23 — "But if ye will not do so, behold, ye have sinned against the LORD: and be sure your sin will find you out." This is one of Scripture''s most quoted proverbs.'),
('Numbers', 32, 'adults', 5, 'What do Jair''s and Nobah''s actions in Numbers 32:41-42 illustrate about the settlement of Transjordan?', 'Only designated tribal leaders could name cities', 'Individual men of valor also took and named towns independently as personal conquests', 'Manasseh claimed the most land of all tribes east of Jordan', 'The land was divided by lot as with the western tribes', 'a', 'Numbers 32:41-42 — "And Jair the son of Manasseh went and took the small towns thereof, and called them Havoth-jair. And Nobah went and took Kenath, and the villages thereof, and called it Nobah, after his own name."'),
('Numbers', 32, 'adults', 6, 'How does the crossing of the Jordan by the Transjordan tribes serve as a type or foreshadowing?', 'It prefigures Gentiles joining Israel in worship', 'It typifies those who serve alongside the body of Christ even when their own inheritance lies elsewhere', 'It shows that the law of Moses could be set aside by tribal agreement', 'It demonstrates that obedience to earthly leaders supersedes God''s commands', 'a', 'Numbers 32:17-18 — Reuben and Gad fully participated in the corporate conquest before returning to personal inheritance, typifying the principle of bearing one another''s burdens before seeking personal reward.'),
('Numbers', 32, 'adults', 7, 'What geographical and theological significance does the Jabbok River have in relation to the territory assigned to Gad?', 'It served as a natural boundary that Gad defended against Ammon', 'It was the site of Jacob''s wrestling with the angel, now within Gad''s tribal land', 'The Jabbok was the source of water for Gad''s cities', 'It was the border between Gad and Manasseh''s portions', 'a', 'Numbers 32:35 — Gad''s territory included Jazer and the region of Gilead near the Jabbok. Genesis 32:22 records Jacob''s wrestling with God at the ford of Jabbok, giving the land patriarchal significance.'),
('Numbers', 32, 'adults', 8, 'What does Moses'' acceptance of Reuben and Gad''s counter-proposal demonstrate about biblical covenant negotiation?', 'Moses had authority to override God''s allotment of land', 'God''s servant can accommodate legitimate requests within the framework of covenant obedience', 'The tribal leaders had equal authority with Moses', 'The land east of Jordan was always intended for these tribes', 'a', 'Numbers 32:25-27 — "Thy servants will do as my lord commandeth...we will pass over armed before the LORD into the land of Canaan." Moses accepted the offer once faithfulness to the whole community was guaranteed, showing covenant flexibility within obedience.');

-- ═══ Numbers Chapter 33 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 33, 'kids', 1, 'From which city did Israel begin their journey out of Egypt?', 'Rameses', 'Memphis', 'Goshen', 'Alexandria', 'a', 'Numbers 33:3 — "And they departed from Rameses in the first month, on the fifteenth day of the first month."'),
('Numbers', 33, 'kids', 2, 'Who wrote down all the places where Israel stopped during their journey?', 'Aaron', 'Joshua', 'Moses', 'Eleazar', 'a', 'Numbers 33:2 — "And Moses wrote their goings out according to their journeys by the commandment of the LORD."'),
('Numbers', 33, 'kids', 3, 'What did God tell Israel to do with the altars of the Canaanites when they entered the land?', 'Destroy them and throw down their images', 'Leave them alone', 'Use them for worship', 'Give them to the Levites', 'a', 'Numbers 33:52 — "then ye shall drive out all the inhabitants...and destroy all their pictures, and destroy all their molten images, and quite pluck down all their high places."'),
-- Teens
('Numbers', 33, 'teens', 1, 'How many stopping places (stages) does Numbers 33 record for Israel''s journey from Egypt to Moab?', 'Forty-two', 'Thirty', 'Fifty', 'Twenty-four', 'a', 'Numbers 33:1-49 lists forty-two camping stations from Rameses to the plains of Moab. This is confirmed by counting the named stations in the chapter.'),
('Numbers', 33, 'teens', 2, 'What significant event does Numbers 33 note happened to Aaron at Mount Hor?', 'He received the priestly garments', 'He died at the age of a hundred and twenty and three years', 'He saw the promised land from the mountain', 'He was given a second set of stone tablets', 'a', 'Numbers 33:38-39 — "And Aaron the priest went up into mount Hor at the commandment of the LORD, and died there...Aaron was an hundred and twenty and three years old when he died."'),
('Numbers', 33, 'teens', 3, 'What was Israel encamped by at the end of their journeys, before entering Canaan?', 'The plains of Moab by Jordan near Jericho', 'The banks of the Red Sea', 'The foot of Mount Sinai', 'The city of Kadesh-barnea', 'a', 'Numbers 33:48-49 — "they pitched in the plains of Moab by Jordan near Jericho...from Beth-jesimoth even unto Abel-shittim in the plains of Moab."'),
('Numbers', 33, 'teens', 4, 'What warning did God give Israel about not driving out all the Canaanites?', 'Those remaining would be as pricks and thorns and would vex Israel', 'Israel would lose their inheritance', 'The Canaanites would join Israel and corrupt the priesthood', 'God would give the land back to the Canaanites', 'a', 'Numbers 33:55 — "But if ye will not drive out the inhabitants of the land from before you; then...those which ye let remain of them shall be pricks in your eyes, and thorns in your sides."'),
('Numbers', 33, 'teens', 5, 'In what month and on what date did Israel leave Egypt, and what was happening in Egypt at that time?', 'The fifteenth day of the first month, on the day after the Passover', 'The first day of the seventh month, at the Feast of Tabernacles', 'The tenth day of the first month, before the Passover', 'The seventh day of the first month, after the plagues ended', 'a', 'Numbers 33:3 — "they departed from Rameses in the first month, on the fifteenth day of the first month; on the morrow after the passover the children of Israel went out."'),
-- Adults
('Numbers', 33, 'adults', 1, 'What does the phrase "by the commandment of the LORD" in Numbers 33:2 indicate about the itinerary record?', 'Moses compiled it from memory at the end of his life', 'God specifically directed Moses to record these journeys, making them divinely authoritative history', 'The Levites compiled it from tribal records', 'Joshua later added the itinerary to Moses'' original account', 'a', 'Numbers 33:2 — "And Moses wrote their goings out according to their journeys by the commandment of the LORD." The divine command to record underscores that Israel''s wilderness journey was providentially ordered and preserved.'),
('Numbers', 33, 'adults', 2, 'What theological significance does Numbers 33:4 attach to the Exodus from Egypt?', 'Israel left because they had completed their time of service', 'The Exodus was God''s judgment on Egypt''s gods, executed through the death of the firstborn', 'God drove Israel out so Pharaoh could not enslave them again', 'The plagues purified Egypt before Israel''s departure', 'a', 'Numbers 33:4 — "For the Egyptians buried all their firstborn, which the LORD had smitten...upon their gods also the LORD executed judgments." The Exodus is explicitly framed as divine judgment on Egypt''s false gods.'),
('Numbers', 33, 'adults', 3, 'What is the significance of the stop at Marah mentioned in this itinerary in light of Exodus 15?', 'Marah was where Israel first sang a song to God', 'Marah''s bitter waters were healed by Moses casting a tree into them, prefiguring Christ on the cross making bitter things sweet', 'Marah was Israel''s first encampment after crossing the Red Sea', 'Marah was the place God gave Israel the manna', 'a', 'The stop at Marah (Num. 33:8-9; Exod. 15:23-25) records where bitter waters were healed by a tree. Many commentators see this as a type of the cross of Christ making the bitter waters of life sweet through his sacrifice.'),
('Numbers', 33, 'adults', 4, 'What detail about Aaron''s death at Mount Hor is stated in Numbers 33:38 that gives it a covenant-calendar significance?', 'He died on the same day of the year as the golden calf incident', 'He died on the first day of the fifth month in the fortieth year, marking the end of the generation that left Egypt', 'He died during the Feast of Weeks', 'He died on the Sabbath day, making it a day of rest', 'a', 'Numbers 33:38 — "Aaron the priest went up into mount Hor at the commandment of the LORD, and died there, in the fortieth year after the children of Israel were come out of the land of Egypt, in the first day of the fifth month." This date marks the passing of the Exodus generation.'),
('Numbers', 33, 'adults', 5, 'What is the total span of wilderness wandering implied by comparing Numbers 33:38 with Numbers 1:1?', 'Exactly forty years from the Exodus to Aaron''s death', 'Thirty-eight years from Kadesh to the Jordan crossing', 'Twenty years from Sinai to Moab', 'Forty years from the giving of the law to the conquest', 'a', 'Numbers 1:1 dates the census to the second year of the Exodus. Numbers 33:38 dates Aaron''s death to the fortieth year. The forty-two stages thus span nearly forty years of wilderness wandering under divine judgment.'),
('Numbers', 33, 'adults', 6, 'How does the command to destroy Canaanite high places in Numbers 33:52 connect to the later failures recorded in Judges?', 'Israel did destroy all the high places and thus succeeded in the conquest', 'Israel''s repeated failure to destroy Canaanite altars fulfilled God''s warning that the remaining peoples would be pricks and thorns', 'The high places were preserved as historical monuments by Joshua''s command', 'The command only applied to the central highlands, not all of Canaan', 'a', 'Numbers 33:55 warns of pricks and thorns if Canaanites remain. Judges 2:2-3 records that Israel did not obey and God confirmed the warning. The New Testament uses this as a lesson on incomplete obedience to God''s commands.'),
('Numbers', 33, 'adults', 7, 'What literary function does the itinerary of Numbers 33 serve within the broader structure of the Pentateuch?', 'It provides a geographic survey for later military campaigns', 'It creates a theological retrospective showing God''s faithfulness through forty years of providential leading despite Israel''s rebellion', 'It serves as legal documentation of tribal land claims', 'It is an appendix added by a later editor to fill gaps in the narrative', 'a', 'Numbers 33:1-2 frames the itinerary as "these are the journeys of the children of Israel." The list of stages bearing witness to God''s sustained provision and guidance makes it a doxological document within the Torah''s narrative.'),
('Numbers', 33, 'adults', 8, 'What does God''s command in Numbers 33:53 — "ye shall dispossess the inhabitants...and dwell therein" — establish theologically about Canaan?', 'Israel had a prior claim to Canaan from the time of Adam', 'Divine gift of land requires active human obedience to appropriate the inheritance', 'The land belonged to Israel purely by right of conquest', 'God would give the land without any effort from Israel', 'a', 'Numbers 33:53 — "ye shall dispossess the inhabitants...for I have given you the land to possess it." The divine gift and the human responsibility to act are held together, a pattern seen throughout Scripture in the relationship between grace and faith.');

-- ═══ Numbers Chapter 34 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 34, 'kids', 1, 'What large body of water formed the western border of the land God promised Israel?', 'The Great Sea (Mediterranean)', 'The Red Sea', 'The Sea of Galilee', 'The Dead Sea', 'a', 'Numbers 34:6 — "And as for the western border, ye shall even have the great sea for a border."'),
('Numbers', 34, 'kids', 2, 'Who was chosen to divide the land of Canaan among the tribes?', 'Eleazar the priest and Joshua', 'Moses and Aaron', 'The twelve tribal chiefs alone', 'Joshua and Caleb', 'a', 'Numbers 34:17 — "These are the names of the men which shall divide the land unto you: Eleazar the priest, and Joshua the son of Nun."'),
('Numbers', 34, 'kids', 3, 'How many tribes would receive an inheritance in the land of Canaan (west of Jordan)?', 'Nine and a half tribes', 'Twelve tribes', 'Ten tribes', 'Eleven tribes', 'a', 'Numbers 34:13-15 — "This is the land which ye shall inherit by lot...for the nine tribes, and for the half tribe: For the tribe of Reuben and the tribe of Gad have received their inheritance...and half the tribe of Manasseh have received their inheritance."'),
-- Teens
('Numbers', 34, 'teens', 1, 'What was the southern border of Canaan as described in Numbers 34?', 'From the wilderness of Zin along Edom to the Salt Sea', 'From the river of Egypt to the Red Sea', 'From Kadesh-barnea to Mount Hor', 'From the wilderness of Sinai to the plains of Moab', 'a', 'Numbers 34:3 — "Then your south quarter shall be from the wilderness of Zin along by the coast of Edom, and your south border shall be the outmost coast of the salt sea eastward."'),
('Numbers', 34, 'teens', 2, 'What was the northern border landmark mentioned as a key point in Numbers 34?', 'Mount Hor to the entrance of Hamath', 'Mount Hermon to Damascus', 'The river Euphrates to the sea', 'Mount Lebanon to the Arnon', 'a', 'Numbers 34:7-8 — "And this shall be your north border: from the great sea ye shall point out for you mount Hor: From mount Hor ye shall point out your border unto the entrance of Hamath."'),
('Numbers', 34, 'teens', 3, 'What was the eastern border of Canaan described as in Numbers 34?', 'From Hazar-enan down to the sea of Chinnereth and along the Jordan to the Salt Sea', 'From the river Euphrates to the Jordan River', 'From Mount Hermon to the Dead Sea along the Jordan', 'From the Arnon River to the Sea of Galilee', 'a', 'Numbers 34:11-12 — "the border shall go down...to the sea of Chinnereth...the border shall go down to Jordan, and the goings out of it shall be at the salt sea."'),
('Numbers', 34, 'teens', 4, 'Why were only nine and a half tribes assigned land west of the Jordan?', 'Reuben, Gad, and half of Manasseh had already received their inheritance east of the Jordan', 'The tribe of Levi did not receive a territorial inheritance', 'Two tribes had been merged during the wilderness', 'Joshua and Caleb were counted as a single tribe', 'a', 'Numbers 34:14-15 — "For the tribe of Reuben...and the tribe of Gad...and half the tribe of Manasseh have received their inheritance...beyond Jordan near Jericho eastward."'),
('Numbers', 34, 'teens', 5, 'One prince from each of the nine and a half tribes was named to help divide the land. Which tribe''s prince was Caleb the son of Jephunneh?', 'The tribe of Judah', 'The tribe of Ephraim', 'The tribe of Simeon', 'The tribe of Issachar', 'a', 'Numbers 34:19 — "Of the tribe of Judah, Caleb the son of Jephunneh." Caleb, one of the faithful spies, represented Judah in the land division.'),
-- Adults
('Numbers', 34, 'adults', 1, 'What is the "ascent of Akrabbim" mentioned as part of the southern border in Numbers 34:4?', 'A mountain pass in the Negev region near Edom known as Scorpion Pass', 'A river crossing in the Sinai Peninsula', 'A hill near Kadesh used as a landmark for tribal boundaries', 'A road leading from Egypt to Canaan', 'a', 'Numbers 34:4 — "And your border shall turn from the south to the ascent of Akrabbim." Akrabbim means "scorpions" in Hebrew and refers to a rocky pass in the southern Negev, identified with Naqb es-Safa.'),
('Numbers', 34, 'adults', 2, 'What theological significance do the borders of Canaan in Numbers 34 have in relation to God''s covenant with Abraham?', 'They represent a partial fulfillment of the Abrahamic land promise, with the full extent described in Genesis 15:18', 'They establish the permanent and final borders of Israel for all time', 'They are entirely different from the Abrahamic promise because sin reduced the land given', 'They define the land of Canaan as all of the Middle East', 'a', 'Numbers 34 defines the inheritance of Canaan given by lot. Genesis 15:18 describes broader boundaries "from the river of Egypt unto the great river, the river Euphrates," which many scholars see as the ideal Davidic-Solomonic fulfillment, while Numbers 34 gives the immediate conquest borders.'),
('Numbers', 34, 'adults', 3, 'What is the Sea of Chinnereth mentioned as the eastern border landmark in Numbers 34:11, and what is its New Testament name?', 'It is the Sea of Galilee, also called Lake Tiberias, where Jesus performed many miracles', 'It is the Dead Sea, also called the Salt Sea', 'It is the Mediterranean Sea, also called the Great Sea', 'It is the Sea of Reeds, also called the Red Sea', 'a', 'Numbers 34:11 — "the border shall reach unto the side of the sea of Chinnereth eastward." This is the Sea of Galilee (John 6:1 calls it "the sea of Tiberias"), where Jesus walked on water and called his disciples.'),
('Numbers', 34, 'adults', 4, 'What is the literary and legal significance of appointing one prince per tribe to supervise the land division?', 'It prevented Moses from having too much authority over the allocation', 'It ensured tribal representation, accountability, and fairness in the sacred process of dividing God''s covenantal gift', 'It was a concession to the tribal leaders who had complained about the allocation', 'It guaranteed that stronger tribes could not claim more land than weaker ones', 'a', 'Numbers 34:18 — "And ye shall take one prince of every tribe, to divide the land by inheritance." This representative system ensured that each tribe''s interests were protected in the divinely superintended distribution.'),
('Numbers', 34, 'adults', 5, 'What does the inclusion of Caleb the son of Jephunneh among the land distributors signify about God''s faithfulness?', 'Caleb was chosen because he was the oldest surviving leader', 'It fulfills the specific promise in Numbers 14:24 that Caleb would enter the land and his seed would possess it', 'Caleb was the most skilled administrator among the tribal leaders', 'Caleb was chosen to honor his father Jephunneh', 'a', 'Numbers 14:24 — "But my servant Caleb...him will I bring into the land whereinto he went; and his seed shall possess it." His role in Numbers 34 as land distributor is the direct fulfillment of God''s earlier promise for his faithfulness.'),
('Numbers', 34, 'adults', 6, 'What Hebrew term underlies the concept of dividing the land "by lot" (Numbers 34:13), and what does it reveal about Israel''s theology of land?', 'Goral — casting lots was considered a divinely directed process revealing God''s sovereign allocation', 'Chelek — indicating equal portions for each tribe regardless of size', 'Nahal — referring to inheritance passed from generation to generation', 'Morasha — meaning possession earned through military victory', 'a', 'Numbers 34:13 — "the land...by lot." The Hebrew practice of goral (lot-casting) is described in Proverbs 16:33 — "The lot is cast into the lap; but the whole disposing thereof is of the LORD." Thus land division was a theological act, not merely administrative.'),
('Numbers', 34, 'adults', 7, 'How does the precise geographical delineation of Canaan''s borders in Numbers 34 serve as evidence for the historicity of these accounts?', 'The borders are entirely symbolic and have no geographic referents', 'The detailed, verifiable place names correspond to known ancient Near Eastern geography and Bronze Age boundary documents', 'The borders were invented by later scribes to justify territorial claims', 'The borders are identical to Egyptian administrative districts of that period, showing copying', 'a', 'Numbers 34 names places like Zin, Akrabbim, Kadesh-barnea, Hazar-addar, Azmon, the river of Egypt, and the Sea of Chinnereth — all verifiable geographical locations consistent with Late Bronze Age Canaan, supporting the historical reliability of the text.'),
('Numbers', 34, 'adults', 8, 'What is the typological significance of Eleazar the priest being placed before Joshua in overseeing the land division?', 'It shows the priest had more authority than the military leader in Israel', 'It typifies the principle that priestly intercession (representing Christ) takes precedence over human leadership in entering God''s rest', 'Eleazar was older than Joshua and thus given precedence by custom', 'The priest was needed to perform ceremonies at each boundary marker', 'a', 'Numbers 34:17 — "Eleazar the priest, and Joshua the son of Nun." Many patristic and Reformed commentators see Eleazar as a type of Christ the High Priest who leads his people into the heavenly inheritance, with Joshua (Yeshua — same name as Jesus) as the type of Christ the conqueror.');

-- ═══ Numbers Chapter 35 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 35, 'kids', 1, 'How many cities were given to the Levites to live in?', 'Forty-eight', 'Twelve', 'Twenty-four', 'Six', 'a', 'Numbers 35:7 — "So all the cities which ye shall give to the Levites shall be forty and eight cities."'),
('Numbers', 35, 'kids', 2, 'What were the special cities called where someone who accidentally killed a person could go for safety?', 'Cities of refuge', 'Holy cities', 'Sanctuary cities', 'Cities of peace', 'a', 'Numbers 35:11 — "Then ye shall appoint you cities to be cities of refuge for you; that the slayer may flee thither, which killeth any person at unawares."'),
('Numbers', 35, 'kids', 3, 'How many cities of refuge were there in total?', 'Six', 'Three', 'Twelve', 'Ten', 'a', 'Numbers 35:13 — "And of these cities which ye shall give six cities shall ye have for refuge."'),
-- Teens
('Numbers', 35, 'teens', 1, 'How were the cities given to the Levites to be distributed among the tribes?', 'Each tribe gave cities in proportion to the size of its inheritance', 'The largest tribes gave the most cities', 'The cities were chosen by lot from each tribe''s inheritance', 'Each tribe gave exactly four cities regardless of size', 'a', 'Numbers 35:8 — "And the cities which ye shall give shall be of the possession of the children of Israel: from them that have many ye shall give many; but from them that have few ye shall give few: every one shall give of his cities unto the Levites according to his inheritance."'),
('Numbers', 35, 'teens', 2, 'Where were the six cities of refuge located — how many on each side of the Jordan?', 'Three on each side of the Jordan River', 'Four west and two east of the Jordan', 'All six were west of the Jordan in Canaan', 'Two in each of three regions: Galilee, Samaria, and Judah', 'a', 'Numbers 35:14 — "Ye shall give three cities on this side Jordan, and three cities shall ye give in the land of Canaan, which shall be cities of refuge."'),
('Numbers', 35, 'teens', 3, 'What was the difference between a murderer and an accidental manslayer under the laws of Numbers 35?', 'A murderer killed with a weapon or in hatred and was to be put to death; an accidental manslayer killed without enmity and could flee to a city of refuge', 'A murderer killed multiple people while a manslayer killed only one', 'A murderer used a weapon while a manslayer used only his hands', 'A murderer was from Israel while a manslayer could be a foreigner', 'a', 'Numbers 35:20-23 distinguishes between killing out of hatred (murder) and killing "suddenly without enmity" (manslaughter), with death as the penalty for murder and the city of refuge as protection for accidental killing.'),
('Numbers', 35, 'teens', 4, 'What happened to an accidental manslayer if he left the city of refuge before the death of the high priest?', 'The avenger of blood could kill him without guilt', 'He was brought back to stand trial again', 'He was sold into slavery to the victim''s family', 'He was banned from Israel forever', 'a', 'Numbers 35:26-27 — "But if the slayer shall at any time come without the border of the city of his refuge...and the revenger of blood kill the slayer; he shall not be guilty of blood."'),
('Numbers', 35, 'teens', 5, 'What was the role of the "revenger of blood" (go''el hadam) in the legal system described in Numbers 35?', 'The nearest kinsman of the murder victim who had the right to execute the convicted murderer', 'A judge appointed by the congregation to oversee capital cases', 'A Levite assigned to carry out all death sentences in Israel', 'An avenger appointed by the high priest for each case', 'a', 'Numbers 35:19 — "The revenger of blood himself shall slay the murderer: when he meeteth him, he shall slay him." The go''el hadam was the next of kin responsible for executing lawful vengeance on a convicted murderer.'),
-- Adults
('Numbers', 35, 'adults', 1, 'What was the size of the common land (suburbs) surrounding each Levitical city?', 'Two thousand cubits from the city wall outward on each side, with one thousand cubits for pasture', 'One thousand cubits on all sides', 'Five hundred cubits for houses and five hundred for fields', 'Three thousand cubits from the center of the city outward', 'a', 'Numbers 35:4-5 — "the suburbs of the cities...shall be a thousand cubits round about...And ye shall measure from without the city on the east side two thousand cubits." The text describes both a 1,000-cubit pasture zone and a 2,000-cubit outer boundary.'),
('Numbers', 35, 'adults', 2, 'What theological principle underlies the law that land sold by a Levite could be redeemed at any time and automatically returned in the Jubilee?', 'The Levites were too poor to have permanent land and needed special protection', 'Since the LORD was the Levites'' inheritance, their city property could not be permanently alienated — they held it in trust', 'The Jubilee laws only applied to Levitical cities, not to the other tribes', 'Levites were exempt from the normal property laws of Israel', 'a', 'Numbers 35:2-3 and Lev. 25:32-34 together establish that Levitical city property was inalienable, reflecting that "the LORD is their inheritance" (Num. 18:20). Their cities were a sacred provision, not a commercial asset.'),
('Numbers', 35, 'adults', 3, 'What is the significance of the manslayer''s release from the city of refuge being tied to the death of the high priest?', 'The high priest''s death was a payment that symbolically atoned for the unintentional bloodshed and released the manslayer from liability', 'The high priest died so old that waiting for his death was a long punishment', 'The release marked a new administration under the next high priest', 'The manslayer was released when the high priest interceded on his behalf', 'a', 'Numbers 35:25,28 — the manslayer "shall abide in it unto the death of the high priest." Patristically and typologically, the high priest''s death is seen as a vicarious atonement that releases the guilty party — a type of Christ whose death releases sinners from condemnation.'),
('Numbers', 35, 'adults', 4, 'How many witnesses were required to impose the death penalty for murder under Numbers 35?', 'At least two witnesses; one witness alone was insufficient', 'Three witnesses from the community', 'The testimony of the victim''s family was sufficient', 'The judge alone could convict based on evidence', 'a', 'Numbers 35:30 — "Whoso killeth any person, the murderer shall be put to death by the mouth of witnesses: but one witness shall not testify against any person to cause him to die." This establishes the foundational legal principle repeated in Deuteronomy 17:6 and Matthew 18:16.'),
('Numbers', 35, 'adults', 5, 'What was the explicit prohibition regarding accepting a ransom payment in murder cases, and what was the theological rationale?', 'No ransom could be accepted for a murderer''s life because blood pollutes the land and only the murderer''s blood could make atonement', 'Ransom was prohibited because it would create inequality between rich and poor', 'The prohibition applied only to premeditated murder, not crimes of passion', 'Ransom was forbidden only in cases where the victim was a Levite', 'a', 'Numbers 35:31,33 — "Moreover ye shall take no satisfaction for the life of a murderer...for blood it defileth the land...and the land cannot be cleansed of the blood that is shed therein, but by the blood of him that shed it."'),
('Numbers', 35, 'adults', 6, 'What is the Hebrew word for the "avenger of blood" (go''el hadam), and how does it connect to the broader concept of redemption in the Old Testament?', 'Go''el — the kinsman-redeemer, the same word used for Boaz in Ruth, linking blood-vengeance and redemption in the same covenantal concept', 'Shaphat — the judge who executes sentence on the murderer', 'Dayyan — the appointed representative of the victim', 'Nagid — the leader who represented the family before the congregation', 'a', 'Numbers 35:19 — "The revenger (go''el) of blood himself shall slay the murderer." The same Hebrew root go''el describes both the avenger of blood and the kinsman-redeemer (Ruth 2:20; Isa. 59:20), showing that redemption and just retribution are two faces of the same covenantal obligation to protect the family.'),
('Numbers', 35, 'adults', 7, 'How do the six cities of refuge serve as a type of Christ in Christian typology?', 'The cities provided a place of safety where the guilty could flee and find complete protection — as Christ is the refuge for sinners fleeing divine judgment', 'The six cities represent the six days of creation, reminding Israel that God rests from judgment', 'The cities are types of the six dispensations of biblical history', 'The number six is the number of man, showing the cities were for human benefit only', 'a', 'Numbers 35:11-12 — "cities of refuge...that the slayer may flee thither." Hebrews 6:18 uses "fled for refuge" language about believers fleeing to Christ. The city that provided absolute protection upon entry typifies Christ, in whom there is "therefore now no condemnation" (Romans 8:1).'),
('Numbers', 35, 'adults', 8, 'What is the theological import of the statement "the land cannot be cleansed of the blood that is shed therein, but by the blood of him that shed it" in Numbers 35:33?', 'It establishes that the land has a moral character before God and that unpunished murder defiles not just individuals but the whole community and its covenantal relationship with God', 'It is a purely judicial statement about forensic guilt with no theological meaning', 'It shows that capital punishment was the only form of punishment Israel used', 'It teaches that land ownership is contingent on the moral purity of its inhabitants', 'a', 'Numbers 35:33-34 — "So ye shall not pollute the land wherein ye are: for blood it defileth the land...defile not therefore the land which ye shall inhabit, wherein I dwell: for I the LORD dwell among the children of Israel." The land''s holiness flows from God''s presence, making murder a theological and not merely criminal matter.');

-- ═══ Numbers Chapter 36 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 36, 'kids', 1, 'Whose daughters had received land as their inheritance, which caused the leaders to bring a question to Moses?', 'Zelophehad''s daughters', 'Caleb''s daughters', 'Aaron''s daughters', 'Joshua''s daughters', 'a', 'Numbers 36:2 — "The LORD commanded my lord to give the land for an inheritance by lot to the children of Israel: and my lord was commanded by the LORD to give the inheritance of Zelophehad our brother unto his daughters."'),
('Numbers', 36, 'kids', 2, 'What problem did the tribal leaders worry about if Zelophehad''s daughters married men from other tribes?', 'Their land would leave their tribe and go to another tribe', 'The daughters would have to move far away', 'The land would be sold to strangers', 'Other tribes would become too powerful', 'a', 'Numbers 36:3 — "And if they be married to any of the sons of the other tribes of the children of Israel, then shall their inheritance be taken from the inheritance of our fathers, and shall be put to the inheritance of the tribe whereunto they are married."'),
('Numbers', 36, 'kids', 3, 'What did God command Zelophehad''s daughters to do so that the land stayed in their tribe?', 'Marry only men from their own tribe of Manasseh', 'Give the land to their male cousins', 'Sell the land back to the tribe''s leaders', 'Wait until the Jubilee to receive their land', 'a', 'Numbers 36:6 — "This is the thing which the LORD doth command concerning the daughters of Zelophehad, saying, Let them marry to whom they think best; only to the family of the tribe of their father shall they marry."'),
-- Teens
('Numbers', 36, 'teens', 1, 'Which tribe were Zelophehad''s daughters from, and who brought the concern to Moses?', 'The tribe of Manasseh; the heads of the fathers of the families of Gilead, son of Machir, son of Manasseh', 'The tribe of Judah; Caleb and the elders of Judah', 'The tribe of Gad; the commanders of the eastern Jordan clans', 'The tribe of Ephraim; the princes chosen for the land division', 'a', 'Numbers 36:1 — "And the chief fathers of the families of the children of Gilead, the son of Machir, the son of Manasseh, of the families of the sons of Joseph, came near, and spake before Moses."'),
('Numbers', 36, 'teens', 2, 'What rule about inheritance and the Year of Jubilee is mentioned in Numbers 36:4?', 'In the Jubilee the inheritance would be added to the tribe into which the daughters married, permanently transferring it', 'In the Jubilee years all land reverts to the tribe of Levi', 'The Jubilee only affected land sold to strangers, not inherited land', 'The Jubilee year would cancel all female inheritance rights', 'a', 'Numbers 36:4 — "And when the jubile of the children of Israel shall be, then shall their inheritance be put unto the inheritance of the tribe whereunto they are married: and from the inheritance of the tribe of our fathers shall it be taken away."'),
('Numbers', 36, 'teens', 3, 'What were the names of Zelophehad''s five daughters who obeyed Moses'' command?', 'Mahlah, Tirzah, Hoglah, Milcah, and Noah', 'Rachel, Leah, Dinah, Tamar, and Miriam', 'Abigail, Hannah, Deborah, Ruth, and Esther', 'Zipporah, Jochebed, Rahab, Naomi, and Orpah', 'a', 'Numbers 36:11 — "For Mahlah, Tirzah, and Hoglah, and Milcah, and Noah, the daughters of Zelophehad, were married unto their father''s brothers'' sons."'),
('Numbers', 36, 'teens', 4, 'What general principle was established for all Israelite women who inherited tribal land?', 'Every daughter who inherits land must marry within her father''s tribe', 'Only unmarried women could hold land inheritance', 'Women could only hold land until they produced a male heir', 'Land inherited by women became the property of their husbands upon marriage', 'a', 'Numbers 36:8 — "And every daughter, that possesseth an inheritance in any tribe of the children of Israel, shall be wife unto one of the family of the tribe of her father, that the children of Israel may enjoy every man the inheritance of his fathers."'),
('Numbers', 36, 'teens', 5, 'Where and when does Numbers 36 conclude, and what does this suggest about the book''s literary structure?', 'In the plains of Moab by Jordan near Jericho, forming a closing bracket with the setting established in Numbers 22, showing the book ends poised for the conquest', 'At Mount Sinai, completing the laws given at Sinai', 'In the wilderness of Zin after the death of Miriam', 'At Kadesh-barnea after the report of the spies', 'a', 'Numbers 36:13 — "These are the commandments and the judgments, which the LORD commanded by the hand of Moses unto the children of Israel in the plains of Moab by Jordan near Jericho." This closing statement mirrors Numbers 22:1 and brackets the Moab legal corpus.'),
-- Adults
('Numbers', 36, 'adults', 1, 'How does the legal problem in Numbers 36 develop the case established in Numbers 27 regarding Zelophehad''s daughters?', 'Numbers 27 granted daughters the right to inherit in the absence of sons; Numbers 36 adds the condition that heiresses must marry within their tribe to prevent tribal land loss', 'Numbers 27 gave only a temporary inheritance; Numbers 36 makes it permanent', 'Numbers 36 overturns Numbers 27 by limiting women''s inheritance rights', 'Both chapters address the same case with no development between them', 'a', 'Numbers 27:7-8 established the principle of female inheritance for sonless families. Numbers 36 extends the ruling by addressing the unintended consequence of inter-tribal marriage, refining the law without overturning it — demonstrating the organic development of Mosaic case law.'),
('Numbers', 36, 'adults', 2, 'What does the phrase "the inheritance shall not remove from one tribe to another tribe" reveal about Israel''s tribal theology of land?', 'Each tribe''s land portion was a sacred covenantal grant from God that was to remain perpetually within the tribe as a testimony to God''s faithfulness', 'The tribes were suspicious of one another and used land law to prevent conflict', 'The rule was purely economic to maintain tribal productivity', 'Moses invented the rule without divine instruction to resolve a political dispute', 'a', 'Numbers 36:9 — "Neither shall the inheritance remove from one tribe to another tribe; but every one of the tribes of the children of Israel shall keep himself to his own inheritance." The tribal land allocations were God''s sovereign gift, and their permanence bore testimony to covenant faithfulness across generations.'),
('Numbers', 36, 'adults', 3, 'How does the Jubilee complication in Numbers 36:4 demonstrate the unity of the Mosaic legal code?', 'It shows that the Jubilee law of Leviticus 25 and the inheritance law of Numbers 27 must be read together as a coherent legal system, with each ruling affecting the interpretation of the other', 'It demonstrates that the Jubilee only benefited the wealthy landowning tribes', 'It shows the Jubilee was originally designed for Levites only and was later expanded', 'It reveals a contradiction between Leviticus and Numbers that later editors tried to harmonize', 'a', 'Numbers 36:4 cites the Jubilee (Lev. 25:10-13) in its argumentation, showing the compilers of Torah intended its laws to function as an integrated system. The tribal leaders'' concern demonstrates practical legal reasoning across multiple statutes.'),
('Numbers', 36, 'adults', 4, 'What does the marriage of Zelophehad''s daughters to their cousins (Numbers 36:11) illustrate about endogamy in ancient Israel?', 'Marriage within the clan (endogamy) was a recognized social structure that preserved both property and family identity within the tribal system', 'Cousin marriage was required for all Israelites to maintain tribal purity', 'The daughters had no choice in the matter and were forced to marry their cousins', 'Endogamy was a temporary measure until the land was divided by lot', 'a', 'Numbers 36:11-12 — "they were married unto their father''s brothers'' sons." Endogamy (intra-clan marriage) appears throughout the patriarchal narratives (Gen. 24:4, 28:2) and in Ruth, where the kinsman-redeemer is from the same family. It served both social cohesion and property preservation functions.'),
('Numbers', 36, 'adults', 5, 'What is the significance of Numbers 36:13 as the closing verse of the entire book of Numbers?', 'It provides a colophon summarizing the entire Mosaic legislative corpus delivered in Moab, giving the book a formal literary conclusion', 'It is a liturgical doxology similar to the end of each psalm collection', 'It introduces the theme that will be developed in Deuteronomy', 'It is a later editorial addition not part of the original Mosaic text', 'a', 'Numbers 36:13 — "These are the commandments and the judgments, which the LORD commanded by the hand of Moses." This is a formal Torah colophon, similar in function to Leviticus 27:34. It closes Numbers with the assertion of Mosaic authority and divine origin, preparing the transition to Deuteronomy.'),
('Numbers', 36, 'adults', 6, 'How does the case of Zelophehad''s daughters in Numbers 27 and 36 function within feminist and legal-historical readings of the Torah?', 'It demonstrates that Mosaic law contained mechanisms for expanding rights incrementally through case law precedent, with women appealing to Moses and receiving favorable rulings', 'It proves that women had equal legal standing with men in all areas of Israelite law', 'It shows that women''s legal rights were an innovation of the post-exilic period read back into Moses', 'It illustrates that only wealthy women could appeal to religious authorities for legal protection', 'a', 'Numbers 27:1-7 records the daughters presenting their case before Moses, Eleazar, the princes, and the congregation — and God ruling in their favor. The case establishes a precedent (Num. 27:11) for female inheritance, showing the Torah''s legal system was responsive to justice claims presented through proper channels.'),
('Numbers', 36, 'adults', 7, 'What does Zelophehad''s daughters marrying within the tribe of Manasseh illustrate about the relationship between personal freedom and communal responsibility in biblical ethics?', 'God allowed them to marry "whom they think best" within the tribe — personal choice exercised within God-given covenantal boundaries', 'The daughters had no personal freedom; they were fully bound by tribal law', 'Biblical ethics always prioritizes communal obligation over individual choice without exception', 'The daughters chose their cousins to maximize their inheritance, showing pragmatic rather than principled decision-making', 'a', 'Numbers 36:6 — "Let them marry to whom they think best; only to the family of the tribe of their father shall they marry." The balance of "whom they think best" (personal choice) and "only to the family" (covenantal boundary) models a biblical ethic where freedom operates within covenant structure, not against it.'),
('Numbers', 36, 'adults', 8, 'How does the book of Numbers end thematically, and how does this set up the book of Deuteronomy?', 'Numbers ends with Israel fully constituted as God''s covenant people in the plains of Moab, their legal code refined and their inheritance imminent, perfectly positioned for Moses'' farewell sermons in Deuteronomy', 'Numbers ends with Israel in rebellion and Deuteronomy begins with God''s judgment', 'Numbers concludes with the conquest of Canaan, making Deuteronomy a retrospective', 'Numbers ends inconclusively and Deuteronomy begins the story of Moses'' death', 'a', 'Numbers 36:13 closes with Israel in the plains of Moab, laws complete, tribes organized, and Canaan waiting. Deuteronomy 1:1-5 picks up in the same location with Moses beginning his addresses — "These be the words which Moses spake unto all Israel on this side Jordan." The seamless transition shows the Pentateuch''s unified narrative architecture.');
